from collections import deque
from typing import List, Dict, Tuple, Optional


class FatTree:
    """k-ary fat tree topology."""

    def __init__(self, k: int):
        self.k = k
        self.adj: Dict[int, List[int]] = {}
        self.num_hosts = (k ** 3) // 4
        self.num_switches = 0
        self.host_ids: List[int] = []
        self.build()

    def _node_id(self, layer: int, pod: int, index: int) -> int:
        k = self.k
        if layer == 0:  # hosts
            return pod * (k // 2) + index
        elif layer == 1:  # edge switches
            base = self.num_hosts
            return base + pod * (k // 2) + index
        elif layer == 2:  # aggregation switches
            base = self.num_hosts + self.k * (self.k // 2)
            return base + pod * (k // 2) + index
        else:  # core switches (layer 3)
            base = self.num_hosts + 2 * self.k * (self.k // 2)
            return base + index

    def build(self):
        k = self.k
        half_k = k // 2
        self.adj = {}

        # Create all node IDs
        all_nodes = set()

        for pod in range(k):
            for i in range(half_k):
                host = self._node_id(0, pod, i)
                edge = self._node_id(1, pod, i // 1)  # each edge switch gets hosts
                all_nodes.add(host)

        # Build connections
        # Hosts to edge switches: each edge switch connects to k/2 hosts
        for pod in range(k):
            for edge_idx in range(half_k):
                edge = self._node_id(1, pod, edge_idx)
                # This edge switch connects to 1 host (simplified: 1 host per edge port)
                host = self._node_id(0, pod, edge_idx)
                self.adj.setdefault(host, []).append(edge)
                self.adj.setdefault(edge, []).append(host)
                self.host_ids.append(host)

                # Edge to aggregation: each edge connects to all agg switches in pod
                for agg_idx in range(half_k):
                    agg = self._node_id(2, pod, agg_idx)
                    self.adj.setdefault(edge, []).append(agg)
                    self.adj.setdefault(agg, []).append(edge)

        # Aggregation to core switches
        for pod in range(k):
            for agg_idx in range(half_k):
                agg = self._node_id(2, pod, agg_idx)
                for core_offset in range(half_k):
                    core_idx = agg_idx * half_k + core_offset
                    core = self._node_id(3, 0, core_idx)
                    self.adj.setdefault(agg, []).append(core)
                    self.adj.setdefault(core, []).append(agg)

        self.num_hosts = k * (k // 2)
        self.host_ids = list(set(self.host_ids))

    def _bfs(self, start: int) -> Dict[int, int]:
        dist = {start: 0}
        queue = deque([start])
        while queue:
            node = queue.popleft()
            for neighbor in self.adj.get(node, []):
                if neighbor not in dist:
                    dist[neighbor] = dist[node] + 1
                    queue.append(neighbor)
        return dist

    def diameter(self) -> int:
        max_dist = 0
        for host in self.host_ids:
            dists = self._bfs(host)
            for other_host in self.host_ids:
                if other_host in dists:
                    max_dist = max(max_dist, dists[other_host])
        return max_dist

    def bisection_bandwidth(self, link_bw_gbps: float) -> float:
        return self.num_hosts * link_bw_gbps

    def route(self, src: int, dst: int) -> List[int]:
        if src == dst:
            return [src]
        dist = {src: 0}
        parent = {src: None}
        queue = deque([src])
        while queue:
            node = queue.popleft()
            if node == dst:
                break
            for neighbor in self.adj.get(node, []):
                if neighbor not in dist:
                    dist[neighbor] = dist[node] + 1
                    parent[neighbor] = node
                    queue.append(neighbor)
        path = []
        node = dst
        while node is not None:
            path.append(node)
            node = parent.get(node)
        return list(reversed(path))


class Torus:
    """k-ary n-dimensional torus."""

    def __init__(self, k: int, n: int):
        self.k = k
        self.n = n
        self.adj: Dict[int, List[int]] = {}
        self.total_nodes = k ** n
        self.build()

    def _coords_to_id(self, coords: Tuple[int, ...]) -> int:
        node_id = 0
        for i, c in enumerate(coords):
            node_id = node_id * self.k + c
        return node_id

    def _id_to_coords(self, node_id: int) -> Tuple[int, ...]:
        coords = []
        for _ in range(self.n):
            coords.append(node_id % self.k)
            node_id //= self.k
        return tuple(reversed(coords))

    def build(self):
        self.adj = {}
        for nid in range(self.total_nodes):
            coords = self._id_to_coords(nid)
            neighbors = []
            for dim in range(self.n):
                for delta in [-1, 1]:
                    new_coords = list(coords)
                    new_coords[dim] = (coords[dim] + delta) % self.k
                    neighbor_id = self._coords_to_id(tuple(new_coords))
                    neighbors.append(neighbor_id)
            self.adj[nid] = neighbors

    def diameter(self) -> int:
        return self.n * (self.k // 2)

    def bisection_bandwidth(self, link_bw_gbps: float) -> float:
        return 2 * (self.k ** (self.n - 1)) * link_bw_gbps

    def route(self, src: int, dst: int) -> List[int]:
        """Dimension-order routing."""
        path = [src]
        src_coords = list(self._id_to_coords(src))
        dst_coords = list(self._id_to_coords(dst))
        current = list(src_coords)

        for dim in range(self.n):
            while current[dim] != dst_coords[dim]:
                # Choose shortest direction (torus wrap)
                diff = (dst_coords[dim] - current[dim]) % self.k
                if diff <= self.k // 2:
                    current[dim] = (current[dim] + 1) % self.k
                else:
                    current[dim] = (current[dim] - 1) % self.k
                path.append(self._coords_to_id(tuple(current)))
        return path


class Dragonfly:
    """Dragonfly topology with parameters p, a, h."""

    def __init__(self, p: int, a: int, h: int):
        self.p = p
        self.a = a
        self.h = h
        self.num_groups = a * h + 1
        self.adj: Dict[int, List[int]] = {}
        self.host_ids: List[int] = []
        self.switch_ids: List[int] = []
        self.build()

    def _switch_id(self, group: int, index: int) -> int:
        total_hosts = self.num_groups * self.a * self.p
        return total_hosts + group * self.a + index

    def _host_id(self, group: int, switch_idx: int, port: int) -> int:
        return (group * self.a + switch_idx) * self.p + port

    def build(self):
        self.adj = {}

        # Connect hosts to their switches
        for g in range(self.num_groups):
            for s in range(self.a):
                sw = self._switch_id(g, s)
                self.switch_ids.append(sw)
                for port in range(self.p):
                    host = self._host_id(g, s, port)
                    self.host_ids.append(host)
                    self.adj.setdefault(host, []).append(sw)
                    self.adj.setdefault(sw, []).append(host)

        # Intra-group: all-to-all among switches
        for g in range(self.num_groups):
            for s1 in range(self.a):
                for s2 in range(s1 + 1, self.a):
                    sw1 = self._switch_id(g, s1)
                    sw2 = self._switch_id(g, s2)
                    self.adj.setdefault(sw1, []).append(sw2)
                    self.adj.setdefault(sw2, []).append(sw1)

        # Inter-group: connect pairs of groups
        # Each pair of groups gets one global link
        # Assign links round-robin to switches within each group
        link_count = {}  # track links per switch
        for sw in self.switch_ids:
            link_count[sw] = 0

        for g1 in range(self.num_groups):
            for g2 in range(g1 + 1, self.num_groups):
                # Find switch in g1 and g2 with fewest global links
                s1_idx = min(range(self.a), key=lambda s: link_count[self._switch_id(g1, s)])
                s2_idx = min(range(self.a), key=lambda s: link_count[self._switch_id(g2, s)])
                sw1 = self._switch_id(g1, s1_idx)
                sw2 = self._switch_id(g2, s2_idx)
                self.adj.setdefault(sw1, []).append(sw2)
                self.adj.setdefault(sw2, []).append(sw1)
                link_count[sw1] += 1
                link_count[sw2] += 1

    def _bfs(self, start: int) -> Dict[int, int]:
        dist = {start: 0}
        parent = {start: None}
        queue = deque([start])
        while queue:
            node = queue.popleft()
            for neighbor in self.adj.get(node, []):
                if neighbor not in dist:
                    dist[neighbor] = dist[node] + 1
                    parent[neighbor] = node
                    queue.append(neighbor)
        return dist

    def diameter(self) -> int:
        max_dist = 0
        # Sample hosts for efficiency
        sample = self.host_ids[:min(len(self.host_ids), 20)]
        for host in sample:
            dists = self._bfs(host)
            for other in self.host_ids:
                if other in dists:
                    max_dist = max(max_dist, dists[other])
        return max_dist

    def route(self, src: int, dst: int) -> List[int]:
        if src == dst:
            return [src]
        dist = {src: 0}
        parent = {src: None}
        queue = deque([src])
        while queue:
            node = queue.popleft()
            if node == dst:
                break
            for neighbor in self.adj.get(node, []):
                if neighbor not in dist:
                    dist[neighbor] = dist[node] + 1
                    parent[neighbor] = node
                    queue.append(neighbor)
        path = []
        node = dst
        while node is not None:
            path.append(node)
            node = parent.get(node)
        return list(reversed(path))

import random
from collections import defaultdict, deque
from typing import List, Dict, Tuple
from dataclasses import dataclass


@dataclass
class CongestionResult:
    link_utilization: Dict[Tuple[int,int], int]
    max_utilization: int
    bottleneck_link: Tuple[int, int]
    avg_utilization: float
    total_flows: int
    max_throughput_per_flow: float


def generate_uniform_random(N: int, seed: int = 42) -> List[Tuple[int, int]]:
    """Each node sends to one random other node."""
    rng = random.Random(seed)
    traffic = []
    for src in range(N):
        dst = src
        while dst == src:
            dst = rng.randint(0, N - 1)
        traffic.append((src, dst))
    return traffic


def generate_nearest_neighbor(N: int, k: int, n_dims: int) -> List[Tuple[int, int]]:
    """Each node sends to its +1 neighbor in dimension 0."""
    traffic = []
    for src in range(N):
        # Decode coords
        coords = []
        tmp = src
        for _ in range(n_dims):
            coords.append(tmp % k)
            tmp //= k
        coords = list(reversed(coords))
        # +1 in dimension 0
        coords[0] = (coords[0] + 1) % k
        # Encode back
        dst = 0
        for c in coords:
            dst = dst * k + c
        traffic.append((src, dst))
    return traffic


def generate_all_to_all(N: int) -> List[Tuple[int, int]]:
    """Every node sends to every other node."""
    traffic = []
    for src in range(N):
        for dst in range(N):
            if src != dst:
                traffic.append((src, dst))
    return traffic


def shortest_path_bfs(adj: Dict[int, List[int]], src: int, dst: int) -> List[int]:
    """BFS shortest path."""
    if src == dst:
        return [src]
    visited = {src}
    parent = {src: None}
    queue = deque([src])
    while queue:
        node = queue.popleft()
        if node == dst:
            break
        for nb in adj.get(node, []):
            if nb not in visited:
                visited.add(nb)
                parent[nb] = node
                queue.append(nb)
    if dst not in parent:
        return []
    path = []
    node = dst
    while node is not None:
        path.append(node)
        node = parent[node]
    return list(reversed(path))


def simulate_congestion(
    adj: Dict[int, List[int]],
    traffic: List[Tuple[int, int]],
    link_bw_gbps: float
) -> CongestionResult:
    """Simulate traffic and measure link congestion."""
    link_load: Dict[Tuple[int,int], int] = defaultdict(int)

    for src, dst in traffic:
        path = shortest_path_bfs(adj, src, dst)
        for i in range(len(path) - 1):
            u, v = path[i], path[i + 1]
            # Use canonical edge (min, max) for undirected
            edge = (min(u, v), max(u, v))
            link_load[edge] += 1

    if not link_load:
        return CongestionResult(
            link_utilization={},
            max_utilization=0,
            bottleneck_link=(0, 0),
            avg_utilization=0.0,
            total_flows=len(traffic),
            max_throughput_per_flow=link_bw_gbps,
        )

    max_load = max(link_load.values())
    bottleneck = max(link_load.items(), key=lambda x: x[1])[0]
    avg_load = sum(link_load.values()) / len(link_load) if link_load else 0

    return CongestionResult(
        link_utilization=dict(link_load),
        max_utilization=max_load,
        bottleneck_link=bottleneck,
        avg_utilization=avg_load,
        total_flows=len(traffic),
        max_throughput_per_flow=link_bw_gbps / max_load if max_load > 0 else link_bw_gbps,
    )
